SELECT IIf([Sales Line.Document Type]=1,"SALES",IIf([Sales Line.Document Type]=5,"RETURNS","")) AS DocumentType, IIf([Order Type]=1,"Riass.",IIf([order type]=2,"Pronto",IIf([order type]=3,"Stock",IIf([order type]=4,"Sost.",IIf([order type]=0,"Progr",IIf([order type]=5,"PreSeason",IIf([order type]=17,"Commerciale",IIf([order type]=18,"Selection","?")))))))) AS OrderType, [Sales Header].No_, [Sales Header].[Salesperson Code], Salesperson_Purchaser.Name AS Salesperson, [Sales Header].[Bill-to Customer No_], [Sales Header].[Bill-to Name], [Sales Header].[Sell-to Customer No_], Customer.Name AS [Sell-to Name], Customer.City, [Sales Header].[Payment Terms Code], [Sales Header].[Payment Method Code], Val([Sales Header.Invoice Discount Value]) AS ScontoFattura, IIf([Consignment]=True,"SI","NO") AS ContoVendita, Item.[trademark code], [Sales Line].[season code], IIf([Sales Line.document type]=1,Val([Amount Including VAT]),0) AS ValueSoldVAT, Val([Right on Return _]) AS PercentualeDirittoAlReso, IIf([Sales Line.document type]=1,Val([No_ of Pairs]),-Val([No_ of Pairs])) AS PairsSold, IIf([Sales Line.document type]=1,(Val([Line Amount])-Val([Inv_ Discount Amount])),-(Val([Line Amount])-Val([Inv_ Discount Amount]))) AS ValueSold, IIf(Val([quantity])>0,Val([quantity shipped])/Val([quantity])*Val([no_ of pairs]),0) AS PairsShipped, IIf(Val([quantity])>0,Val([quantity shipped])/Val([quantity])*[ValueSold],0) AS ValueShipped, Customer.[Current Risk], Customer.[risk rating], Customer.[Blocked for Assignments], Customer.[Reason Block Code], Customer.[Geographical Zone], [Geographical Zone].Description AS GeoZone1Description, Customer.[Geographical Zone 2], [Geographical Zone_1].Description AS GeoZone2Description, [Sales Header].[Securities Received], [Sales Line].[requested delivery date], Customer.[Credit Manager], IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[PaiaInBollaTotale]) AS PairsReadyForShipping, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,IIf(Val([quantity])>0,Nz([quantitainbollatotale])/Val([quantity])*[ValueSold],0)) AS ValueReadyForShipping, Customer.[Purchase Group]
FROM ((((((((((([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document Type] = [Sales Header].[Document Type]) AND ([Sales Line].[Document No_] = [Sales Header].No_)) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group]) AND ([Sales Line].[Constant Variable Code] = [Variable Code].[Variable Code])) LEFT JOIN [Shipment Method] ON [Sales Header].[Shipment Method Code] = [Shipment Method].Code) LEFT JOIN Salesperson_Purchaser AS Salesperson_Purchaser_1 ON [Sales Header].[Area Manager Code] = Salesperson_Purchaser_1.Code) LEFT JOIN Salesperson_Purchaser AS Salesperson_Purchaser_2 ON [Sales Header].[Subject 1] = Salesperson_Purchaser_2.Code) LEFT JOIN Salesperson_Purchaser AS Salesperson_Purchaser_3 ON [Sales Header].[Subject 2] = Salesperson_Purchaser_3.Code) INNER JOIN Customer ON [Sales Header].[Sell-to Customer No_] = Customer.No_) INNER JOIN Item ON [Sales Line].No_ = Item.No_) LEFT JOIN [Geographical Zone] ON Customer.[Geographical Zone] = [Geographical Zone].Code) LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON Customer.[Geographical Zone 2] = [Geographical Zone_1].Code) LEFT JOIN [qsoloVend-DatiBolleAperteRilasciate] ON ([Sales Line].[Line No_] = [qsoloVend-DatiBolleAperteRilasciate].[Order Line No_]) AND ([Sales Line].[Document No_] = [qsoloVend-DatiBolleAperteRilasciate].[Order No_])
WHERE (((IIf([Sales Line.Document Type]=1,"SALES",IIf([Sales Line.Document Type]=5,"RETURNS","")))="SALES") AND (([Sales Line].Type)=20 Or ([Sales Line].Type)=19) AND ((Item.[advertising material])=0) AND (([Sales Line].[Delete Reason])=""));

